try:
    X_val, y_val
except NameError:
    raise NameError("X_val/y_val not in scope. Re-run the data-loading cell before this one.")

CLASS_NAMES = ["Normal", "Supra", "PVC", "Fusion", "Unknown"]
N_CLASSES = 5
CLASS_QRS_ANCHOR = {0: (60, 125), 1: (20, 110), 2: (50, 130), 3: (60, 130)}  # Unknown excluded — trivial anchor
GLOBAL_QRS_ANCHOR = (67, 118)

import shap
N_BG = 100
N_PER_CLASS = 60   # matches Cell 67's LIME-1D stratification — guarantees every
                   # class, including rare ones like Fusion, actually gets evaluated
rng = np.random.default_rng(42)
bg_idx = rng.choice(len(X_val), size=min(N_BG, len(X_val)), replace=False)
X_bg = torch.tensor(X_val[bg_idx][:, np.newaxis, :], dtype=torch.float32).to(device)

# ── Stratified test set by TRUE label — a random draw left Fusion at n=0
#    and Supra/PVC at single-digit n in the previous run, making those rows
#    statistically meaningless. Sample up to N_PER_CLASS from each class.
test_idx_parts = []
for ci in range(N_CLASSES):
    ci_idx = np.where(y_val == ci)[0]
    n_take = min(N_PER_CLASS, len(ci_idx))
    if n_take < N_PER_CLASS:
        print(f"  [WARNING] Class {CLASS_NAMES[ci]} has only {len(ci_idx)} samples in "
              f"X_val — using all of them, below the {N_PER_CLASS}-per-class target.")
    test_idx_parts.append(rng.choice(ci_idx, size=n_take, replace=False))
test_idx = np.concatenate(test_idx_parts)
rng.shuffle(test_idx)
X_test = X_val[test_idx]
y_test_true = y_val[test_idx]
print(f"[OK] background n={len(X_bg)}  test n={len(X_test)}  "
      f"(stratified by TRUE label, target {N_PER_CLASS}/class)")

explainer = shap.DeepExplainer(model, X_bg)
print("\n[1/2] Computing real SHAP values (DeepExplainer, check_additivity=False — "
      "multi-branch/SE-gated architecture causes a known tolerance mismatch)...")
batch_size = 32
all_sv = []
for start in range(0, len(X_test), batch_size):
    xb = torch.tensor(X_test[start:start+batch_size][:, np.newaxis, :], dtype=torch.float32).to(device)
    sv = explainer.shap_values(xb, check_additivity=False)
    all_sv.append(np.stack(sv, axis=0))
shap_matrix_per_class = np.concatenate(all_sv, axis=1).squeeze(2)
print(f"  SHAP computed  shape={shap_matrix_per_class.shape}")

with torch.no_grad():
    logits = model(torch.tensor(X_test[:, np.newaxis, :], dtype=torch.float32).to(device))
    pred_classes = logits.argmax(1).cpu().numpy()

pred_counts = {CLASS_NAMES[c]: int((pred_classes == c).sum()) for c in range(N_CLASSES)}
true_counts = {CLASS_NAMES[c]: int((y_test_true == c).sum()) for c in range(N_CLASSES)}
print(f"  True label counts (stratified):      {true_counts}")
print(f"  Predicted label counts (model output): {pred_counts}")
if pred_counts["Fusion"] == 0 and true_counts["Fusion"] > 0:
    print(f"  [NOTE] {true_counts['Fusion']} true Fusion samples were fed in, but the "
          f"model predicted Fusion 0 times — this is now confirmed to be real model "
          f"behavior (misclassification into other classes), not a sampling artifact.")

print("\n[2/2] Computing QRS-region trust scores...")
global_scores = np.zeros(len(X_test))
class_scores = np.full(len(X_test), np.nan)
for i in range(len(X_test)):
    pc = pred_classes[i]
    sv_abs = np.abs(shap_matrix_per_class[pc, i])
    total = sv_abs.sum() + 1e-8
    g0, g1 = GLOBAL_QRS_ANCHOR
    global_scores[i] = sv_abs[g0:g1].sum() / total
    if pc in CLASS_QRS_ANCHOR:
        c0, c1 = CLASS_QRS_ANCHOR[pc]
        class_scores[i] = sv_abs[c0:c1].sum() / total

def _verdict(m):
    return "VALID" if m >= 0.50 else ("REVIEW" if m >= 0.28 else "RETRAIN")

g_mean, g_std = global_scores.mean(), global_scores.std()
_vcs = class_scores[~np.isnan(class_scores)]
c_mean, c_std = _vcs.mean(), _vcs.std()

print("\n" + "="*70)
print("  SHAP TRUST SCORE — MultiScaleECGCNN (verified checkpoint)")
print("="*70)
print(f"  Global QRS anchor (67,118)      mean={g_mean:.4f}  std={g_std:.4f}  n={len(X_test)}  {_verdict(g_mean)}")
print(f"  Class-specific anchors (N/S/V/F)  mean={c_mean:.4f}  std={c_std:.4f}  n={len(_vcs)}  {_verdict(c_mean)}")
print("\n  Per-class breakdown:")
for ci, cname in enumerate(CLASS_NAMES):
    mask = pred_classes == ci
    n = int(mask.sum())
    if ci == 4:
        print(f"    {cname:<10}: n={n}  (excluded — anchor spans full signal, trivial score)")
        continue
    if n == 0:
        print(f"    {cname:<10}: no predicted samples in this test batch")
        continue
    print(f"    {cname:<10}: mean={class_scores[mask].mean():.4f}  n={n}  {_verdict(class_scores[mask].mean())}")
print("="*70)

mean_abs_shap = np.stack([np.abs(shap_matrix_per_class[pred_classes[i], i]) for i in range(len(X_test))])
fig, axes = plt.subplots(1, 2, figsize=(16, 7), facecolor="#0d1117")
for ax in axes:
    ax.set_facecolor("#161b22")
    for sp in ax.spines.values(): sp.set_color("#30363d")
    ax.tick_params(colors="#8b949e", labelsize=10)
    ax.grid(color="#30363d", lw=0.4, alpha=0.5)
profile = mean_abs_shap.mean(axis=0)
axes[0].fill_between(range(187), profile, 0, color="#58a6ff", alpha=0.6)
axes[0].plot(profile, color="#58a6ff", lw=1.5)
axes[0].axvspan(*GLOBAL_QRS_ANCHOR, color="#2ea44f", alpha=0.15, label="QRS anchor")
axes[0].set_title("Global Time-Step Importance (real SHAP)", color="#c9d1d9", fontsize=11, loc="left")
axes[0].set_xlabel("Signal Timestep", color="#8b949e"); axes[0].set_ylabel("Mean |SHAP|", color="#8b949e")
axes[0].legend(facecolor="#161b22", labelcolor="#c9d1d9")
for i in range(len(X_test)):
    axes[1].scatter(np.arange(187), mean_abs_shap[i], color="#bc8cff", alpha=0.12, s=4)
axes[1].set_title(f"Attribution Dispersion (n={len(X_test)})", color="#c9d1d9", fontsize=11, loc="left")
axes[1].set_xlabel("Signal Timestep", color="#8b949e")
fig.suptitle(f"SHAP — MultiScaleECGCNN (131,573 params, verified)  |  Global trust={g_mean:.3f} ({_verdict(g_mean)})",
             color="#f0f6fc", fontsize=13, fontweight="bold")
plt.tight_layout()
plt.savefig(f"{output_dir}/shap_beeswarm_real.png", dpi=300, facecolor="#0d1117", bbox_inches="tight")
plt.close()
print(f"\nSaved: {output_dir}/shap_beeswarm_real.png")
