class MultiBranchGradCAM:
    """Real Grad-CAM: hooks the last conv of each of the 3 parallel paths,
    weights each branch's activation map by its own GAP'd gradient, sums
    across branches, then ReLU + min-max normalize. This is the correct
    approach for a multi-scale architecture with no single 'last conv layer'."""
    def __init__(self, model):
        self.model = model
        self.device = next(model.parameters()).device
        self.target_modules = [model.path_small[4], model.path_medium[4], model.path_large[4]]

    def explain(self, X, target_class=None):
        batch_size = X.shape[0]
        branch_acts = []
        hooks = []
        def make_hook(store):
            def fn(module, inp, out): store.append(out)
            return fn
        for m in self.target_modules:
            store = []
            branch_acts.append(store)
            hooks.append(m.register_forward_hook(make_hook(store)))
        try:
            logits = self.model(X)
            target_classes = logits.argmax(1).detach() if target_class is None else \
                torch.full((batch_size,), target_class, dtype=torch.long, device=self.device)
            one_hot = F.one_hot(target_classes, num_classes=N_CLASSES).float()
            class_scores = (logits * one_hot).sum()
            self.model.zero_grad()

            combined = torch.zeros((batch_size, 187), device=self.device)
            for store in branch_acts:
                act = store[0]                                        # (batch, 48, 187) — real target-layer activations
                grad = torch.autograd.grad(class_scores, act, retain_graph=True)[0]
                weights = grad.mean(dim=2, keepdim=True)               # (batch, 48, 1) — GAP'd gradient, per Selvaraju et al.
                combined += (weights * act).sum(dim=1)                 # weighted combination of the SAME activations, not raw input
            combined = F.relu(combined)
            cmin = combined.amin(dim=1, keepdim=True)
            cmax = combined.amax(dim=1, keepdim=True)
            combined = (combined - cmin) / (cmax - cmin + 1e-8)
            return combined.detach().cpu().numpy(), target_classes.cpu().numpy()
        finally:
            for h in hooks: h.remove()

explainer = MultiBranchGradCAM(model)
print("[OK] Multi-Branch Grad-CAM targeting: path_small.4, path_medium.4, path_large.4")

N_PER_CLASS = 60   # matches Cell 67's LIME-1D stratification and the SHAP cell —
                   # same seed below means all three methods score the SAME samples
rng = np.random.default_rng(42)
test_idx_parts = []
for ci in range(N_CLASSES):
    ci_idx = np.where(y_val == ci)[0]
    n_take = min(N_PER_CLASS, len(ci_idx))
    if n_take < N_PER_CLASS:
        print(f"  [WARNING] Class {CLASS_NAMES[ci]} has only {len(ci_idx)} samples in "
              f"X_val — using all of them, below the {N_PER_CLASS}-per-class target.")
    test_idx_parts.append(rng.choice(ci_idx, size=n_take, replace=False))
test_idx = np.concatenate(test_idx_parts)
rng.shuffle(test_idx)
X_test = X_val[test_idx]
y_test_true = y_val[test_idx]

gradcam_matrix = np.zeros((len(X_test), 187))
pred_classes = np.zeros(len(X_test), dtype=int)

print(f"[OK] test n={len(X_test)}  device={device}  (stratified by TRUE label, target {N_PER_CLASS}/class)")
print("\n[1/2] Computing Grad-CAM attributions (real target-layer gradients)...")
batch_size = 32
for start in range(0, len(X_test), batch_size):
    end = min(start + batch_size, len(X_test))
    xb = torch.tensor(X_test[start:end][:, np.newaxis, :], dtype=torch.float32).to(device)
    cam, preds = explainer.explain(xb, target_class=None)
    gradcam_matrix[start:end] = cam
    pred_classes[start:end] = preds
print(f"  Grad-CAM computed  shape={gradcam_matrix.shape}")

pred_counts = {CLASS_NAMES[c]: int((pred_classes == c).sum()) for c in range(N_CLASSES)}
true_counts = {CLASS_NAMES[c]: int((y_test_true == c).sum()) for c in range(N_CLASSES)}
print(f"  True label counts (stratified):      {true_counts}")
print(f"  Predicted label counts (model output): {pred_counts}")
if pred_counts["Fusion"] == 0 and true_counts["Fusion"] > 0:
    print(f"  [NOTE] {true_counts['Fusion']} true Fusion samples were fed in, but the "
          f"model predicted Fusion 0 times — confirmed real model behavior, not a "
          f"sampling artifact.")
if min(pred_counts.values()) < 5:
    print("  [WARNING] One or more predicted classes still has <5 samples even with "
          "stratified true labels — that class's trust score below will be noisy.")

print("\n[2/2] Computing QRS-region trust scores (Unknown excluded — see header note)...")
global_scores = np.zeros(len(X_test))
class_scores = np.full(len(X_test), np.nan)
for i in range(len(X_test)):
    pc = pred_classes[i]
    cam_abs = np.abs(gradcam_matrix[i])
    total = cam_abs.sum() + 1e-8
    g0, g1 = GLOBAL_QRS_ANCHOR
    global_scores[i] = cam_abs[g0:g1].sum() / total
    if pc in CLASS_QRS_ANCHOR:
        c0, c1 = CLASS_QRS_ANCHOR[pc]
        class_scores[i] = cam_abs[c0:c1].sum() / total

def _verdict(m):
    if m >= 0.50: return "VALID"
    if m >= 0.28: return "REVIEW"
    return "RETRAIN"

g_mean, g_std = global_scores.mean(), global_scores.std()
valid_class_scores = class_scores[~np.isnan(class_scores)]
c_mean, c_std = valid_class_scores.mean(), valid_class_scores.std()

print("\n" + "="*70)
print("  GRAD-CAM TRUST SCORE — MultiScaleECGCNN (verified checkpoint)")
print("="*70)
print(f"  Global QRS anchor (67,118)      mean={g_mean:.4f}  std={g_std:.4f}  n={len(X_test)}  {_verdict(g_mean)}")
print(f"  Class-specific anchors (N/S/V/F only)  mean={c_mean:.4f}  std={c_std:.4f}  n={len(valid_class_scores)}  {_verdict(c_mean)}")
print("\n  Per-class breakdown:")
for ci, cname in enumerate(CLASS_NAMES):
    mask = pred_classes == ci
    n = int(mask.sum())
    if ci == 4:
        print(f"    {cname:<10}: n={n}  (excluded from tiers — no fixed morphology, anchor spans full signal)")
        continue
    if n == 0:
        print(f"    {cname:<10}: no predicted samples in this test batch")
        continue
    m = class_scores[mask].mean()
    print(f"    {cname:<10}: mean={m:.4f}  n={n}  {_verdict(m)}")
print("="*70)

fig, axes = plt.subplots(1, 2, figsize=(16, 7), facecolor="#0d1117")
for ax in axes:
    ax.set_facecolor("#161b22")
    for sp in ax.spines.values(): sp.set_color("#30363d")
    ax.tick_params(colors="#8b949e", labelsize=10)
    ax.grid(color="#30363d", lw=0.4, alpha=0.5)

profile = gradcam_matrix.mean(axis=0)
axes[0].fill_between(range(187), profile, 0, color="#79c0ff", alpha=0.6)
axes[0].plot(profile, color="#79c0ff", lw=1.5)
axes[0].axvspan(*GLOBAL_QRS_ANCHOR, color="#2ea44f", alpha=0.15, label="QRS anchor")
axes[0].set_title("Global Time-Step Importance (Grad-CAM, real target-layer gradients)",
                   color="#c9d1d9", fontsize=11, loc="left")
axes[0].set_xlabel("Signal Timestep", color="#8b949e")
axes[0].set_ylabel("Mean Grad-CAM", color="#8b949e")
axes[0].legend(facecolor="#161b22", labelcolor="#c9d1d9")

for i in range(len(X_test)):
    axes[1].scatter(np.arange(187), gradcam_matrix[i], color="#d29922", alpha=0.12, s=4)
axes[1].set_title(f"Attribution Dispersion  (n={len(X_test)} real samples)",
                   color="#c9d1d9", fontsize=11, loc="left")
axes[1].set_xlabel("Signal Timestep", color="#8b949e")

fig.suptitle(f"Grad-CAM — MultiScaleECGCNN (131,573 params, verified checkpoint)  |  "
             f"Global trust={g_mean:.3f} ({_verdict(g_mean)})",
             color="#f0f6fc", fontsize=13, fontweight="bold")
plt.tight_layout()
plt.savefig(f"{output_dir}/gradcam_beeswarm_real.png", dpi=300, facecolor="#0d1117", bbox_inches="tight")
plt.close()
print(f"\nSaved: {output_dir}/gradcam_beeswarm_real.png")
print("[DONE] Grad-CAM trust score complete")

